function navavishkar_stay_table_insert(&$error_message = '') {
	global $Translation;

	// mm: can member insert record?
	$arrPerm = getTablePermissions('navavishkar_stay_table');
	if(!$arrPerm['insert']) {
		$error_message = $Translation['no insert permission'];
		return false;
	}

	$data = [
		'username' => parseCode('<%%creatorUsername%%>', true),
		'full_name' => Request::val('full_name', ''),
		'emp_id' => Request::val('emp_id', ''),
		'department' => Request::val('department', ''),
		'designation' => Request::val('designation', ''),
		'contact_email' => Request::val('contact_email', ''),
		'contact_number' => Request::val('contact_number', ''),
		'room_number' => Request::val('room_number', ''),
		'check_in_date' => Request::dateComponents('check_in_date', '1'),
		'checkout_date' => Request::dateComponents('checkout_date', '1'),
		'reason_for_stay' => br2nl(Request::val('reason_for_stay', '')),
		'approval_status' => Request::val('approval_status', 'Under Consideration'),
		'approval_remarks' => br2nl(Request::val('approval_remarks', '')),
		'created_by' => parseCode('<%%creatorUsername%%>', true),
		'created_at' => parseCode('<%%creationDateTime%%>', true),
	];

	// record owner is current user
	$recordOwner = getLoggedMemberID();

	$recID = tableInsert('navavishkar_stay_table', $data, $recordOwner, $error_message);

	// if this record is a copy of another record, copy children if applicable
	if(strlen(Request::val('SelectedID')) && $recID !== false)
		navavishkar_stay_table_copy_children($recID, Request::val('SelectedID'));

	return $recID;
}

function navavishkar_stay_table_copy_children($destination_id, $source_id) {
	global $Translation;
	$requests = []; // array of curl handlers for launching insert requests
	$eo = ['silentErrors' => true];
	$safe_sid = makeSafe($source_id);
	$currentUsername = getLoggedMemberID();
	$errorMessage = '';

	// launch requests, asynchronously
	curl_batch($requests);
}

function navavishkar_stay_table_delete($selected_id, $AllowDeleteOfParents = false, $skipChecks = false) {
	// insure referential integrity ...
	global $Translation;
	$selected_id = makeSafe($selected_id);

	// mm: can member delete record?
	if(!check_record_permission('navavishkar_stay_table', $selected_id, 'delete')) {
		return $Translation['You don\'t have enough permissions to delete this record'];
	}

	// hook: navavishkar_stay_table_before_delete
	if(function_exists('navavishkar_stay_table_before_delete')) {
		$args = [];
		if(!navavishkar_stay_table_before_delete($selected_id, $skipChecks, getMemberInfo(), $args))
			return $Translation['Couldn\'t delete this record'] . (
				!empty($args['error_message']) ?
					'<div class="text-bold">' . strip_tags($args['error_message']) . '</div>'
					: ''
			);
	}

	// child table: navavishkar_stay_payment_table
	$res = sql("SELECT `id` FROM `navavishkar_stay_table` WHERE `id`='{$selected_id}'", $eo);
	$id = db_fetch_row($res);
	$rires = sql("SELECT COUNT(1) FROM `navavishkar_stay_payment_table` WHERE `navavishakr_stay_details`='" . makeSafe($id[0]) . "'", $eo);
	$rirow = db_fetch_row($rires);
	$childrenATag = '<a class="alert-link" href="navavishkar_stay_payment_table_view.php?filterer_navavishakr_stay_details=' . urlencode($id[0]) . '">%s</a>';
	if($rirow[0] && !$AllowDeleteOfParents && !$skipChecks) {
		$RetMsg = $Translation["couldn't delete"];
		$RetMsg = str_replace('<RelatedRecords>', sprintf($childrenATag, $rirow[0]), $RetMsg);
		$RetMsg = str_replace(['[<TableName>]', '<TableName>'], sprintf($childrenATag, 'navavishkar_stay_payment_table'), $RetMsg);
		return $RetMsg;
	} elseif($rirow[0] && $AllowDeleteOfParents && !$skipChecks) {
		$RetMsg = $Translation['confirm delete'];
		$RetMsg = str_replace('<RelatedRecords>', sprintf($childrenATag, $rirow[0]), $RetMsg);
		$RetMsg = str_replace(['[<TableName>]', '<TableName>'], sprintf($childrenATag, 'navavishkar_stay_payment_table'), $RetMsg);
		$RetMsg = str_replace('<Delete>', '<input type="button" class="btn btn-danger" value="' . html_attr($Translation['yes']) . '" onClick="window.location = `navavishkar_stay_table_view.php?SelectedID=' . urlencode($selected_id) . '&delete_x=1&confirmed=1&csrf_token=' . urlencode(csrf_token(false, true)) . (Request::val('Embedded') ? '&Embedded=1' : '') . '`;">', $RetMsg);
		$RetMsg = str_replace('<Cancel>', '<input type="button" class="btn btn-success" value="' . html_attr($Translation[ 'no']) . '" onClick="window.location = `navavishkar_stay_table_view.php?SelectedID=' . urlencode($selected_id) . (Request::val('Embedded') ? '&Embedded=1' : '') . '`;">', $RetMsg);
		return $RetMsg;
	}

	sql("DELETE FROM `navavishkar_stay_table` WHERE `id`='{$selected_id}'", $eo);

	// hook: navavishkar_stay_table_after_delete
	if(function_exists('navavishkar_stay_table_after_delete')) {
		$args = [];
		navavishkar_stay_table_after_delete($selected_id, getMemberInfo(), $args);
	}

	// mm: delete ownership data
	sql("DELETE FROM `membership_userrecords` WHERE `tableName`='navavishkar_stay_table' AND `pkValue`='{$selected_id}'", $eo);
}

function navavishkar_stay_table_update(&$selected_id, &$error_message = '') {
	global $Translation;

	// mm: can member edit record?
	if(!check_record_permission('navavishkar_stay_table', $selected_id, 'edit')) return false;

	$data = [
		'full_name' => Request::val('full_name', ''),
		'emp_id' => Request::val('emp_id', ''),
		'department' => Request::val('department', ''),
		'designation' => Request::val('designation', ''),
		'contact_email' => Request::val('contact_email', ''),
		'contact_number' => Request::val('contact_number', ''),
		'room_number' => Request::val('room_number', ''),
		'check_in_date' => Request::dateComponents('check_in_date', ''),
		'checkout_date' => Request::dateComponents('checkout_date', ''),
		'reason_for_stay' => br2nl(Request::val('reason_for_stay', '')),
		'approval_status' => Request::val('approval_status', ''),
		'approval_remarks' => br2nl(Request::val('approval_remarks', '')),
		'last_updated_by' => parseCode('<%%editorUsername%%>', false),
		'last_updated_at' => parseCode('<%%editingDateTime%%>', false),
	];

	// get existing values
	$old_data = getRecord('navavishkar_stay_table', $selected_id);
	if(is_array($old_data)) {
		$old_data = array_map('makeSafe', $old_data);
		$old_data['selectedID'] = makeSafe($selected_id);
	}

	$data['selectedID'] = makeSafe($selected_id);

	// hook: navavishkar_stay_table_before_update
	if(function_exists('navavishkar_stay_table_before_update')) {
		$args = ['old_data' => $old_data];
		if(!navavishkar_stay_table_before_update($data, getMemberInfo(), $args)) {
			if(isset($args['error_message'])) $error_message = $args['error_message'];
			return false;
		}
	}

	$set = $data; unset($set['selectedID']);
	foreach ($set as $field => $value) {
		$set[$field] = ($value !== '' && $value !== NULL) ? $value : NULL;
	}

	if(!update(
		'navavishkar_stay_table',
		backtick_keys_once($set),
		['`id`' => $selected_id],
		$error_message
	)) {
		echo $error_message;
		echo '<a href="navavishkar_stay_table_view.php?SelectedID=' . urlencode($selected_id) . "\">{$Translation['< back']}</a>";
		exit;
	}


	update_calc_fields('navavishkar_stay_table', $data['selectedID'], calculated_fields()['navavishkar_stay_table']);

	// hook: navavishkar_stay_table_after_update
	if(function_exists('navavishkar_stay_table_after_update')) {
		if($row = getRecord('navavishkar_stay_table', $data['selectedID'])) $data = array_map('makeSafe', $row);

		$data['selectedID'] = $data['id'];
		$args = ['old_data' => $old_data];
		if(!navavishkar_stay_table_after_update($data, getMemberInfo(), $args)) return;
	}

	// mm: update record update timestamp
	set_record_owner('navavishkar_stay_table', $selected_id);
}

